INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, 0, "春咲 ひより", 1, 2, 1001, 1, 1, 0, 0, "お！\nあそこに困ってそうな人発見！", 1.4, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("みんなみたいに\nわたしも強くならなきゃ", 0, 0, "草野 優衣", 1, 2, 1002, 1, 1, 0, 0, "大切な人を\n守れるようになりたい…って", 1.4, "わ、わたし、\nなに言ってるんだろ\nあはは…", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("フェンシングを始めてみては？", 0, 0, "士条 怜", 1, 2, 1003, 1, 1, 0, 0, "キミに必要な集中力と感性が", 1.4, "少しは磨かれると思いますよ。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ねぇ、にいちゃん！", 0, 0, "穂高 みそぎ", 1, 2, 1004, 1, 1, 0, 0, "今日はなにして遊ぶ？", 1.5, "みそぎはねぇ、\nかくれんぼやりたい！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("風宮あかりです", 0, 0, "風宮 あかり", 1, 2, 1006, 1, 1, 0, 0, "ねぇ…", 1.4, "私といっしょに…\nいかない？", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("出雲宮子なのー", 0, 0, "出雲 宮子", 1, 2, 1007, 1, 1, 0, 0, "プリンたべたいのー", 1.5, "食べ物の恨みは怖いのー", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ボクは虹村雪。", 0, 0, "虹村 雪", 1, 2, 1008, 1, 1, 0, 0, "キミもボクの美貌に\n吸い寄せられたんだね。", 1.4, "いいよ。\n見られることは運命さ…", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("フッ…聞いて後悔するがいい！", 0, 0, "柊杏奈", 1, 2, 1009, 1, 1, 0, 0, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1.4, "人呼んで「疾風の冥姫」!!", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("マホマホ王国のプリンセス、\nまほ姫どす", 0, 0, "姫宮 真歩", 1, 2, 1010, 1, 1, 0, 0, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1.5, "ほんまおおきにやわ～♪", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("衣之咲璃乃です！", 0, 0, "衣之咲 璃乃", 1, 2, 1011, 1, 1, 0, 0, "生き別れたお兄ちゃんを探して\n三千世界！", 1.4, "ここで会ったが\n100年目～！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, 0, "柏崎 初音", 1, 2, 1012, 1, 1, 0, 0, "ち、超能力って…\n何のことかな～？", 1.4, "…って、お願い！\n誰にも言わないでおいて～！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ちょす！\n美波鈴奈だよ～♪", 0, 0, "美波 鈴奈", 1, 2, 1016, 1, 1, 0, 0, "一応カリスマ読モJKやってまっす！", 1.4, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("はいたーい。\n喜屋武香織さー。", 0, 0, "喜屋武 香織", 1, 2, 1017, 1, 1, 0, 0, "東京は遊園地みたいなところさー", 1.4, "でも、沖縄もとってもいいとこさー", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("支倉伊緒です。", 0, 0, "支倉 伊緒", 1, 2, 1018, 1, 1, 0, 0, "先生って呼ばれるのは\nくすぐったいから", 1.4, "イオちゃんって呼んでね。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, 0, "茜 ミミ", 1, 2, 1020, 1, 1, 0, 0, "あ！/\お兄ちゃ～ん\nまってよ～", 1.5, "ミミをおいてかないでぇ～", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あ…あの…えっと…\n栗…林…くるみ…です……", 0, 0, "栗林 くるみ", 1, 2, 1021, 1, 1, 0, 0, "あの……\nふぇ……", 1.5, "ふぇぇぇぇぇん……", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("風宮よりです。\nあああああ！", 0, 0, "風宮 より", 1, 2, 1022, 1, 1, 0, 0, "こんな私に貴重な時間を\n割いていただき、", 1.4, "なんてありがとうございます！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, 0, "北条 綾音", 1, 2, 1023, 1, 1, 0, 0, "おにいちゃんどこいくの？\nえ？", 1.5, "私こっち行きたいー\nね、早く早くー", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わっ…わっ…私、\n天野すずめといいます！", 0, 0, "天野 すずめ", 1, 2, 1025, 1, 1, 0, 0, "ふ、不束者ですが\nどうぞ末永く…って、", 1.4, "これて何か違う…\nあああすみません！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("……クスクス…私は\n…倉石恵理子……", 0, 0, "倉石 恵理子", 1, 2, 1027, 1, 1, 0, 0, "あなたは…運命の……\n伴侶……", 1.4, "離しませんわ………\n絶対に…!!", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, 0, "佐々木 咲恋", 1, 2, 1028, 1, 1, 0, 0, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1.4, "…そうでしょ？？", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("桜井望だよ！\nよろしくねっ", 0, 0, "桜井 望", 1, 2, 1029, 1, 1, 0, 0, "ぇっと…\nキミ、私のこと知らないの?!", 1.4, "あはは、\n私もまだまだだなぁ～", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("デケデケデンっ！", 0, 0, "ニノン・ジュベール", 1, 2, 1030, 1, 1, 0, 0, "初めまして、\n私はニノン・ジュベール申すデス！", 1.4, "ショーグン、\nワタシと一緒に天下統一デース！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("上喜しのぶです。\n手元のドクロが父です。", 0, 0, "上喜 しのぶ", 1, 2, 1031, 1, 1, 0, 0, "でもって私の隣にいるのが……\nえ、見えない？", 1.4, "おかしいですね……", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("目指すはビッグな\nお笑い芸人だっぺ！", 0, 0, "野戸まひる", 1, 2, 1033, 1, 1, 0, 0, "けんども\nそれには足りないモンが…", 1.5, "そう、\nオラのボケに突っ込める相方が…！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, 0, "綾瀬 ゆかり", 1, 2, 1034, 1, 1, 0, 0, "ちょっと緊張しちゃって…", 1.4, "ちょ\nちょっと一杯飲んできます…！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("氷川鏡華…です", 0, 0, "氷川 鏡華", 1, 2, 1036, 1, 1, 0, 0, "知らない人とは話しちゃいけないので", 1.5, "これ以上お話しすることは…\nないです！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("柏崎…栞です。", 0, 0, "柏崎 栞", 1, 2, 1038, 1, 1, 0, 0, "……あ、アラーム。", 1.4, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ふ、双葉碧です。", 0, 0, "双葉 碧", 1, 2, 1040, 1, 1, 0, 0, "私、一人も友達がいなくて……", 1.4, "野に咲く花が、\n唯一の話相手です。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("三角千歌です。", 0, 0, "三角 千歌", 1, 2, 1042, 1, 1, 0, 0, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1.4, "そう思っています。", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("安芸真琴だ。", 0, 0, "安芸 真琴", 1, 2, 1043, 1, 1, 0, 0, "あぁ？\nお前のそいつの仲間か？", 1.4, "う、疑ってすまなかったな…", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わらわこそは夜を総べる者！", 0, 0, "イリヤ・オーンスタイン", 1, 2, 1044, 1, 1, 0, 0, "生けとし生ける全ての者よ！", 1.4, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そこで騎士は妖精を乱暴に……", 0, 0, "遠見 空花", 1, 2, 1045, 1, 1, 0, 0, "ぐふふふふ……はっ！", 1.4, "ｌク、クウカに何かご用ですか!?", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, 0, "宮坂たまき", 1, 2, 1046, 1, 1, 0, 0, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1.4, "う～ん…\n猫ってホントに最高にゃ～♪", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("大神美冬よ！", 0, 0, "大神 美冬", 1, 2, 1048, 1, 1, 0, 0, "それでは早速クエストに…", 1.4, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("星野静流だよ！", 0, 0, "星野静流", 1, 2, 1049, 1, 1, 0, 0, "クエストもバトルも\n掃除も洗濯も", 1.4, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("アタシは玉泉美咲。", 0, 0, "玉泉美咲", 1, 2, 1050, 1, 1, 0, 0, "見ての通りの\nセクシー美少女で", 1.5, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("？？？", 0, 0, "リマ", 1, 2, 1052, 1, 1, 0, 0, "？？？？", 1.4, "？？？？", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 0, "モニカ・ヴァイスヴィント", 1, 2, 1053, 1, 1, 0, 0, "菓子でつろうなどと\n稚拙な策を……", 1.5, "そ、そこまでいうなら\nもらってやる", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 0, "ペコリーヌ", 1, 2, 1058, 1, 1, 0, 0, "菓子でつろうなどと\n稚拙な策を……", 1.5, "そ、そこまでいうなら\nもらってやる", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 0, "コッコロ", 1, 2, 1059, 1, 1, 0, 0, "菓子でつろうなどと\n稚拙な策を……", 1.5, "そ、そこまでいうなら\nもらってやる", 0);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 0, 0, "キャル", 1, 2, 1060, 1, 1, 0, 0, "菓子でつろうなどと\n稚拙な策を……", 1.5, "そ、そこまでいうなら\nもらってやる", 0);
